




// ABOUT FUNCTION
function aboutFunction (e) {
    const barIconEl = document.querySelectorAll('.about .about-bar .fa');
    const divTextEl = document.querySelector('.about .text');
    const divIloveEl = document.querySelector('.about .ilove');
    const divOnwebEl = document.querySelector('.about .onweb');


    if(e == 0) {
        divTextEl.style.display = 'block';
        divIloveEl.style.display = 'none';
        divOnwebEl.style.display = 'none';

        // ADD nav-style class
        barIconEl[0].classList.add("nav-style");
        barIconEl[1].classList.remove("nav-style");
        barIconEl[2].classList.remove("nav-style");
    }
    else if(e == 1){
        divTextEl.style.display = 'none';
        divIloveEl.style.display = 'block';
        divOnwebEl.style.display = 'none';

        // ADD nav-style class
        barIconEl[0].classList.remove("nav-style");
        barIconEl[1].classList.add("nav-style");
        barIconEl[2].classList.remove("nav-style");
    }
    else if(e == 2){
        divTextEl.style.display = 'none';
        divIloveEl.style.display = 'none';
        divOnwebEl.style.display = 'block';

        // ADD nav-style class
        barIconEl[0].classList.remove("nav-style");
        barIconEl[1].classList.remove("nav-style");
        barIconEl[2].classList.add("nav-style");
    }
}

